module RefModule(clk, IRWr, imOut, instruction);input clk, IRWr;
    input [31:0] imOut;
    output reg [31:0] instruction;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if(IRWr) instruction <= imOut;
        else instruction <= instruction;
    end
endmodule
